     3→import { useState } from "react";
     4→import { useRouter } from "next/navigation";
     5→import { Button } from "@/components/ui/button";
     6→import { Input } from "@/components/ui/input";
     7→import { Label } from "@/components/ui/label";
     8→import { Textarea } from "@/components/ui/textarea";
     9→import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
    10→import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
    11→import type { Project, ProjectInput, SourceInput } from "@/lib/api/types";
    12→import { Plus, X } from "lucide-react";
    13→
    14→export interface ProjectFormResult {
    15→  project: ProjectInput;
    16→  source?: SourceInput;
    17→}
    18→
    19→interface ProjectFormProps {
    20→  initial?: Project;
    21→  onSubmit: (result: ProjectFormResult) => Promise<void>;
    22→  title: string;
    23→  /** Hide the source section (used in edit mode) */
    24→  hideSource?: boolean;
    25→}
    26→
    27→export function ProjectForm({ initial, onSubmit, title, hideSource }: ProjectFormProps) {
    28→  const router = useRouter();
    29→  const [saving, setSaving] = useState(false);
    30→  const [name, setName] = useState(initial?.name ?? "");
    31→  const [description, setDescription] = useState(initial?.description ?? "");
    32→  const [error, setError] = useState("");
    33→
    34→  /* Source fields (only for create) */
    35→  const [showSource, setShowSource] = useState(false);
    36→  const [provider, setProvider] = useState("github");
    37→  const [repository, setRepository] = useState("");
    38→  const [pollInterval, setPollInterval] = useState("300");
    39→
    40→  const handleSubmit = async (e: React.FormEvent) => {
    41→    e.preventDefault();
    42→    setError("");
    43→    setSaving(true);
    44→    try {
    45→      const result: ProjectFormResult = {
    46→        project: {
    47→          name,
    48→          description: description || undefined,
    49→        },
    50→      };
    51→      if (showSource && repository.trim()) {
    52→        result.source = {
    53→          provider,
    54→          repository: repository.trim(),
    55→          poll_interval_seconds: Number(pollInterval) || 300,
    56→          enabled: true,
    57→        };
    58→      }
    59→      await onSubmit(result);
    60→      router.push("/projects");
    61→    } catch (err: unknown) {
    62→      setError(err instanceof Error ? err.message : "Failed to save");
    63→    } finally {
    64→      setSaving(false);
    65→    }
    66→  };
    67→
    68→  return (
    69→    <Card className="mx-auto max-w-2xl">
    70→      <CardHeader>
    71→        <CardTitle>{title}</CardTitle>
    72→      </CardHeader>
    73→      <CardContent>
    74→        <form onSubmit={handleSubmit} className="space-y-4">
    75→          {error && <div className="rounded-md bg-red-50 p-3 text-sm text-red-700">{error}</div>}
    76→          <div className="space-y-2">
    77→            <Label htmlFor="name">Name</Label>
    78→            <Input id="name" value={name} onChange={(e) => setName(e.target.value)} required />
    79→          </div>
    80→          <div className="space-y-2">
    81→            <Label htmlFor="description">Description</Label>
    82→            <Textarea id="description" value={description} onChange={(e) => setDescription(e.target.value)} rows={2} />
    83→          </div>
    84→
    85→          {/* Optional source section — only in create mode */}
    86→          {!hideSource && (
    87→            <div className="space-y-3">
    88→              {!showSource ? (
    89→                <button
    90→                  type="button"
    91→                  onClick={() => setShowSource(true)}
    92→                  className="inline-flex items-center gap-1.5 text-[13px] font-medium transition-colors hover:opacity-80"
    93→                  style={{ color: "#e8601a" }}
    94→                >
    95→                  <Plus className="h-3.5 w-3.5" />
    96→                  Add a Source
