    93→                  style={{ color: "#e8601a" }}
    94→                >
    95→                  <Plus className="h-3.5 w-3.5" />
    96→                  Add a Source
    97→                </button>
    98→              ) : (
    99→                <div className="rounded-md border p-4 space-y-3" style={{ borderColor: "#e8e8e5" }}>
   100→                  <div className="flex items-center justify-between">
   101→                    <Label className="text-[13px] font-medium">Add a Source</Label>
   102→                    <button
   103→                      type="button"
   104→                      onClick={() => { setShowSource(false); setRepository(""); }}
   105→                      className="text-[#9ca3af] hover:text-[#6b7280]"
   106→                    >
   107→                      <X className="h-4 w-4" />
   108→                    </button>
   109→                  </div>
   110→                  <div className="space-y-2">
   111→                    <Label>Provider</Label>
   112→                    <Select value={provider} onValueChange={setProvider}>
   113→                      <SelectTrigger><SelectValue /></SelectTrigger>
   114→                      <SelectContent>
   115→                        <SelectItem value="github">GitHub</SelectItem>
   116→                        <SelectItem value="dockerhub">Docker Hub</SelectItem>
   117→                      </SelectContent>
   118→                    </Select>
   119→                  </div>
   120→                  <div className="space-y-2">
   121→                    <Label htmlFor="repository">Repository</Label>
   122→                    <Input
   123→                      id="repository"
   124→                      value={repository}
   125→                      onChange={(e) => setRepository(e.target.value)}
   126→                      placeholder="e.g. ethereum/go-ethereum"
   127→                    />
   128→                  </div>
