   634→		if err := rows.Scan(&sub.ID, &sub.ChannelID, &sub.Type, &sub.SourceID,
   635→			&sub.ProjectID, &sub.VersionFilter, &sub.CreatedAt); err != nil {
   636→			return nil, fmt.Errorf("scan subscription: %w", err)
