   643→// GetPreviousRelease returns the most recent release for a source that is not
   644→// the given version, ordered by created_at descending. Returns nil (no error)
   645→// if no previous release exists.
   646→func (s *PgStore) GetPreviousRelease(ctx context.Context, sourceID string, beforeVersion string) (*models.Release, error) {
   647→	var rel models.Release
   648→	err := s.pool.QueryRow(ctx,
   649→		`SELECT id, source_id, version, COALESCE(raw_data,'{}'), released_at, created_at
   650→		 FROM releases
   651→		 WHERE source_id = $1 AND version != $2
   652→		 ORDER BY COALESCE(released_at, created_at) DESC
   653→		 LIMIT 1`, sourceID, beforeVersion,
   654→	).Scan(&rel.ID, &rel.SourceID, &rel.Version, &rel.RawData, &rel.ReleasedAt, &rel.CreatedAt)
   655→	if err != nil {
   656→		if err.Error() == "no rows in result set" {
   657→			return nil, nil
   658→		}
   659→		return nil, fmt.Errorf("get previous release: %w", err)
   660→	}
   661→	return &rel, nil
   662→}
