   664→// EnqueueAgentRun creates an agent_run row and enqueues a River AgentJobArgs.
   665→// This follows the transactional outbox pattern for zero-loss guarantee.
   666→func (s *PgStore) EnqueueAgentRun(ctx context.Context, projectID, trigger string) error {
   667→	tx, err := s.pool.Begin(ctx)
   668→	if err != nil {
   669→		return fmt.Errorf("begin tx: %w", err)
   670→	}
   671→	defer tx.Rollback(ctx)
   672→
   673→	var runID string
   674→	err = tx.QueryRow(ctx,
   675→		`INSERT INTO agent_runs (project_id, trigger, status)
   676→		 VALUES ($1, $2, 'pending')
   677→		 RETURNING id`, projectID, trigger,
   678→	).Scan(&runID)
   679→	if err != nil {
   680→		return fmt.Errorf("insert agent run: %w", err)
   681→	}
   682→
   683→	if s.river != nil {
   684→		_, err = s.river.InsertTx(ctx, tx, queue.AgentJobArgs{
   685→			AgentRunID: runID,
   686→			ProjectID:  projectID,
   687→		}, nil)
   688→		if err != nil {
   689→			return fmt.Errorf("enqueue agent job: %w", err)
   690→		}
   691→	}
   692→
   693→	return tx.Commit(ctx)
   694→}
