   698→// UpdateAgentRunStatus sets the status of an agent run and updates the
   699→// started_at timestamp when transitioning to "running".
   700→func (s *PgStore) UpdateAgentRunStatus(ctx context.Context, id, status string) error {
   701→	var query string
   702→	switch status {
   703→	case "running":
   704→		query = `UPDATE agent_runs SET status = $1, started_at = NOW() WHERE id = $2`
   705→	case "completed":
   706→		query = `UPDATE agent_runs SET status = $1, completed_at = NOW() WHERE id = $2`
   707→	default:
   708→		query = `UPDATE agent_runs SET status = $1 WHERE id = $2`
   709→	}
   710→	tag, err := s.pool.Exec(ctx, query, status, id)
   711→	if err != nil {
   712→		return fmt.Errorf("update agent run status: %w", err)
   713→	}
   714→	if tag.RowsAffected() == 0 {
   715→		return fmt.Errorf("agent run not found: %s", id)
   716→	}
   717→	return nil
   718→}
