   720→// CreateSemanticRelease inserts a semantic release and its source release links
   721→// in a single transaction. The sr.ID field is populated on success.
   722→func (s *PgStore) CreateSemanticRelease(ctx context.Context, sr *models.SemanticRelease, releaseIDs []string) error {
   723→	tx, err := s.pool.Begin(ctx)
   724→	if err != nil {
   725→		return fmt.Errorf("begin tx: %w", err)
   726→	}
   727→	defer tx.Rollback(ctx)
   728→
   729→	err = tx.QueryRow(ctx,
   730→		`INSERT INTO semantic_releases (project_id, version, report, status, completed_at)
   731→		 VALUES ($1, $2, $3, $4, $5)
   732→		 RETURNING id, created_at`,
   733→		sr.ProjectID, sr.Version, sr.Report, sr.Status, sr.CompletedAt,
   734→	).Scan(&sr.ID, &sr.CreatedAt)
   735→	if err != nil {
   736→		return fmt.Errorf("insert semantic release: %w", err)
   737→	}
   738→
   739→	for _, relID := range releaseIDs {
   740→		_, err = tx.Exec(ctx,
   741→			`INSERT INTO semantic_release_sources (semantic_release_id, release_id)
   742→			 VALUES ($1, $2) ON CONFLICT DO NOTHING`,
   743→			sr.ID, relID,
   744→		)
   745→		if err != nil {
   746→			return fmt.Errorf("insert semantic release source: %w", err)
   747→		}
   748→	}
   749→
   750→	return tx.Commit(ctx)
   751→}
