    10→
    11→// CheckAgentRules evaluates the agent rules against the new and previous version
    12→// strings. Returns true if any rule matches and an agent run should be triggered.
    13→func CheckAgentRules(rules *models.AgentRules, newVersion, previousVersion string) bool {
    14→	if rules == nil {
    15→		return false
    16→	}
    17→
    18→	newMajor, newMinor, _ := parseVersion(newVersion)
    19→	oldMajor, oldMinor, _ := parseVersion(previousVersion)
    20→
    21→	if rules.OnMajorRelease && newMajor > oldMajor {
    22→		return true
    23→	}
    24→	if rules.OnMinorRelease && (newMajor > oldMajor || newMinor > oldMinor) {
    25→		return true
    26→	}
    27→	if rules.OnSecurityPatch && isSecurityPatch(newVersion) {
    28→		return true
    29→	}
    30→	if rules.VersionPattern != "" {
    31→		if matched, _ := regexp.MatchString(rules.VersionPattern, newVersion); matched {
    32→			return true
    33→		}
    34→	}
    35→	return false
    36→}
    37→
    38→// parseVersion extracts major, minor, patch integers from a version string.
    39→// It tolerates a leading "v" prefix and pre-release suffixes (e.g. "-security").
    40→func parseVersion(v string) (major, minor, patch int) {
    41→	v = strings.TrimPrefix(v, "v")
    42→	parts := strings.SplitN(v, ".", 3)
    43→	if len(parts) >= 1 {
    44→		major, _ = strconv.Atoi(parts[0])
    45→	}
    46→	if len(parts) >= 2 {
    47→		minor, _ = strconv.Atoi(parts[1])
    48→	}
    49→	if len(parts) >= 3 {
    50→		// Strip pre-release suffix (e.g. "4-security" -> "4")
    51→		patchStr := strings.SplitN(parts[2], "-", 2)[0]
    52→		patch, _ = strconv.Atoi(patchStr)
    53→	}
    54→	return
    55→}
    56→
    57→// isSecurityPatch returns true if the version string contains a known security
    58→// keyword in its pre-release or metadata suffix.
    59→func isSecurityPatch(version string) bool {
    60→	lower := strings.ToLower(version)
    61→	keywords := []string{"security", "cve", "vuln"}
    62→	for _, kw := range keywords {
    63→		if strings.Contains(lower, kw) {
    64→			return true
    65→		}
    66→	}
    67→	return false
    68→}
    69→

